import{_ as e,o as s,c as n,ah as t}from"./chunks/framework.DsjyFzT5.js";const h=JSON.parse('{"title":"《Pro Git》笔记","description":"","frontmatter":{"title":"《Pro Git》笔记","date":"2022-07-13T00:00:00.000Z","category":"git","tags":["Reading","git","ing"]},"headers":[],"relativePath":"_post/ide-skill/git/deep-git.md","filePath":"_post/ide-skill/git/deep-git.md"}'),i={name:"_post/ide-skill/git/deep-git.md"};function l(r,a,p,o,d,c){return s(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="《pro-git》笔记" tabindex="-1">《Pro Git》笔记 <a class="header-anchor" href="#《pro-git》笔记" aria-label="Permalink to &quot;《Pro Git》笔记&quot;">​</a></h1><h2 id="git的数据模型" tabindex="-1">git的数据模型 <a class="header-anchor" href="#git的数据模型" aria-label="Permalink to &quot;git的数据模型&quot;">​</a></h2><p>Git 将顶级目录中的文件和文件夹作为集合，并通过一系列快照来管理其历史记录。在Git的术语里，文件被称作Blob对象（数据对象），也就是一组数据。目录则被称之为“树”，它将名字与 Blob 对象或树对象进行映射（使得目录中可以包含其他目录）。快照则是被追踪的最顶层的树。例如，一个树看起来可能是这样的：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;root&gt; (tree)</span></span>
<span class="line"><span>|</span></span>
<span class="line"><span>+- foo (tree)</span></span>
<span class="line"><span>|  |</span></span>
<span class="line"><span>|  + bar.txt (blob, contents = &quot;hello world&quot;)</span></span>
<span class="line"><span>|</span></span>
<span class="line"><span>+- baz.txt (blob, contents = &quot;git is wonderful&quot;)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这个顶层的树包含了两个元素，一个名为 “foo” 的树（它本身包含了一个blob对象 “bar.txt”），以及一个 blob 对象 “baz.txt”。</p><h1 id="随记" tabindex="-1">随记 <a class="header-anchor" href="#随记" aria-label="Permalink to &quot;随记&quot;">​</a></h1><p>SHA-1 哈希：存储的是文件变化的内容？</p><p>Git 用以计算校验和的机制叫做 SHA-1 散列（hash，哈希）。 这是一个由 40 个十六进制字符（0-9 和 a-f）组成的字符串，基于 Git 中文件的内容或目录结构计算出来。 SHA-1 哈希看起来是这样：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>24b9da6552252987aa493b52f8696cd6d3b00373</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to &quot;参考文献&quot;">​</a></h2><ul><li>[1] <a href="https://missing-semester-cn.github.io/2020/version-control/" target="_blank" rel="noreferrer">斯坦福-git</a></li><li>[2] <a href="https://www.progit.cn/" target="_blank" rel="noreferrer">Pro Git 中文版</a></li></ul>`,11)])])}const u=e(i,[["render",l]]);export{h as __pageData,u as default};
